interface DatePickerState {
  open: boolean;
  wasHidden: boolean;
  lastPreSelectChange?:
    | typeof PRESELECT_CHANGE_VIA_INPUT
    | typeof PRESELECT_CHANGE_VIA_NAVIGATE;
  inputValue: string | null;
  preventFocus: boolean;
  preSelection?: CalendarProps["preSelection"];
  shouldFocusDayInline?: CalendarProps["shouldFocusDayInline"];
  monthSelectedIn?: CalendarProps["monthSelectedIn"];
  focused?: CalendarProps["isInputFocused"];
  highlightDates: Required<CalendarProps>["highlightDates"];
  isRenderAriaLiveMessage?: boolean;
}

export class DatePicker extends Component<DatePickerProps, DatePickerState> {
  static get defaultProps() {
    return {
      allowSameDay: false,
      dateFormat: "MM/dd/yyyy",
      dateFormatCalendar: "LLLL yyyy",
      disabled: false,
      disabledKeyboardNavigation: false,
      dropdownMode: "scroll" as const,
      preventOpenOnFocus: false,
      monthsShown: 1,
      outsideClickIgnoreClass: OUTSIDE_CLICK_IGNORE_CLASS,
      readOnly: false,
      rangeSeparator: DATE_RANGE_SEPARATOR,
      withPortal: false,
      selectsDisabledDaysInRange: false,
      shouldCloseOnSelect: true,
      showTimeSelect: false,
      showTimeInput: false,
      showPreviousMonths: false,
      showMonthYearPicker: false,
      showFullMonthYearPicker: false,
      showTwoColumnMonthYearPicker: false,
      showFourColumnMonthYearPicker: false,
      showYearPicker: false,
      showQuarterYearPicker: false,
      showWeekPicker: false,
      strictParsing: false,
      swapRange: false,
      timeIntervals: 30,
      timeCaption: "Time",
      previousMonthAriaLabel: "Previous Month",
      previousMonthButtonLabel: "Previous Month",
      nextMonthAriaLabel: "Next Month",
      nextMonthButtonLabel: "Next Month",
      previousYearAriaLabel: "Previous Year",
      previousYearButtonLabel: "Previous Year",
      nextYearAriaLabel: "Next Year",
      nextYearButtonLabel: "Next Year",
      timeInputLabel: "Time",
      enableTabLoop: true,
      yearItemNumber: DEFAULT_YEAR_ITEM_NUMBER,
      focusSelectedMonth: false,
      showPopperArrow: true,
      excludeScrollbar: true,
      customTimeInput: null,
      calendarStartDay: undefined,
      toggleCalendarOnIconClick: false,
      usePointerEvent: false,
    };
  }

  constructor(props: DatePickerProps) {
    super(props);
    this.state = this.calcInitialState();
    this.preventFocusTimeout = undefined;
  }

  componentDidMount(): void {
    window.addEventListener("scroll", this.onScroll, true);
    document.addEventListener(
      "visibilitychange",
      this.setHiddenStateOnVisibilityHidden,
    );
  }

  componentDidUpdate(
    prevProps: DatePickerProps,
    prevState: DatePickerState,
  ): void {
    if (
      prevProps.inline &&
      hasPreSelectionChanged(prevProps.selected, this.props.selected)
    ) {
      this.setPreSelection(this.props.selected);
    }
    if (
      this.state.monthSelectedIn !== undefined &&
      prevProps.monthsShown !== this.props.monthsShown
    ) {
      this.setState({ monthSelectedIn: 0 });
    }
    if (this.props.selectsRange && this.state.monthSelectedIn !== 0) {
      this.setState({ monthSelectedIn: 0 });
    }
    if (prevProps.highlightDates !== this.props.highlightDates) {
      this.setState({
        highlightDates: getHighLightDaysMap(this.props.highlightDates),
      });
    }
    if (
      !prevState.focused &&
      !isEqual(prevProps.selected, this.props.selected)
    ) {
      this.setState({ inputValue: null });
    }

    if (prevState.open !== this.state.open) {
      if (prevState.open === false && this.state.open === true) {
        this.props.onCalendarOpen?.();
      }

      if (prevState.open === true && this.state.open === false) {
        this.props.onCalendarClose?.();
      }
    }
  }

  componentWillUnmount(): void {
    this.clearPreventFocusTimeout();
    window.removeEventListener("scroll", this.onScroll, true);
    document.removeEventListener(
      "visibilitychange",
      this.setHiddenStateOnVisibilityHidden,
    );
        if (iterations >= MAX_ITERATIONS) {
          newSelection = date;
          break;
        }
        // if minDate exists and the new selection is before the min date, get the nearest date that isn't disabled
        if (minDate && newSelection < minDate) {
          eventKeyCopy = KeyType.ArrowRight;
          newSelection = isDayDisabled(minDate, this.props)
            ? calculateNewDate(eventKeyCopy, newSelection)
            : minDate;
        }

        // if maxDate exists and the new selection is after the max date, get the nearest date that isn't disabled
        if (maxDate && newSelection > maxDate) {
          eventKeyCopy = KeyType.ArrowLeft;
          newSelection = isDayDisabled(maxDate, this.props)
            ? calculateNewDate(eventKeyCopy, newSelection)
            : maxDate;
        }

        if (isDayDisabled(newSelection, this.props)) {
          // if PageUp and Home is pressed to a disabled date, it will try to find the next available date after
          if (
            eventKeyCopy === KeyType.PageUp ||
            eventKeyCopy === KeyType.Home
          ) {
            eventKeyCopy = KeyType.ArrowRight;
          }

          // if PageDown and End is pressed to a disabled date, it will try to find the next available date before
          if (
            eventKeyCopy === KeyType.PageDown ||
            eventKeyCopy === KeyType.End
          ) {
            eventKeyCopy = KeyType.ArrowLeft;
          }
          newSelection = calculateNewDate(eventKeyCopy, newSelection);
        } else {
          validDateFound = true;
        }
        iterations++;
      }

      return newSelection;
    };

    if (eventKey === KeyType.Enter) {
      event.preventDefault();
      this.handleSelect(copy, event);
      !shouldCloseOnSelect && this.setPreSelection(copy);
      return;
    } else if (eventKey === KeyType.Escape) {
      event.preventDefault();

      this.setOpen(false);
      if (!this.inputOk()) {
        this.props.onInputError?.({ code: 1, msg: INPUT_ERR_1 });
      }
      return;
    }

    let newSelection = null;
    switch (eventKey) {
      case KeyType.ArrowLeft:
      case KeyType.ArrowRight:
      case KeyType.ArrowUp:
      case KeyType.ArrowDown:
      case KeyType.PageUp:
      case KeyType.PageDown:
      case KeyType.Home:
      case KeyType.End:
        newSelection = getNewDate(eventKey, copy);
        break;
    }
    if (!newSelection) {
      this.props.onInputError?.({ code: 1, msg: INPUT_ERR_1 });
      return;
    }
    event.preventDefault();
    this.setState({ lastPreSelectChange: PRESELECT_CHANGE_VIA_NAVIGATE });
    if (adjustDateOnChange) {
      this.setSelected(newSelection);
    }
    this.setPreSelection(newSelection);
    // In inline mode, always set shouldFocusDayInline to true when navigating via keyboard.
    // This ensures focus is properly transferred to the new day element regardless of
    // whether the month changed. The user initiated this navigation from a focused day,
    // so we should always focus the destination day.
    if (inline) {
      this.setState({ shouldFocusDayInline: true });
    }
  };

  // handle generic key down events in the popper that do not adjust or select dates
  // ex: while focusing prev and next month buttons
  onPopperKeyDown = (event: React.KeyboardEvent<HTMLDivElement>): void => {
    const eventKey = event.key;
    if (eventKey === KeyType.Escape) {
      event.preventDefault();
      this.sendFocusBackToInput();
      this.setOpen(false);
    }
  };

  onClearClick = (event?: React.MouseEvent<HTMLButtonElement>): void => {
    if (event) {
      if (event.preventDefault) {
        event.preventDefault();
      }
    }

    this.sendFocusBackToInput();

    const { selectsRange, onChange } = this.props;
    if (selectsRange) {
      onChange?.([null, null], event);
    } else {
      onChange?.(null, event);
    }

    this.setState({ inputValue: null });
  };

  clear = () => {
    this.onClearClick();
  };

  onScroll = (event: Event): void => {
    if (
      typeof this.props.closeOnScroll === "boolean" &&
      this.props.closeOnScroll
    ) {
      if (
        event.target === document ||
        event.target === document.documentElement ||
        event.target === document.body
      ) {
        this.setOpen(false);
      }
    } else if (typeof this.props.closeOnScroll === "function") {
      if (this.props.closeOnScroll(event)) {
        this.setOpen(false);
      }
    }
  };

  renderCalendar = () => {
    if (!this.props.inline && !this.isCalendarOpen()) {
      return null;
    }
    return (
      <Calendar
        showMonthYearDropdown={undefined}
        ref={(elem) => {
          this.calendar = elem;
        }}
        {...this.props}
        {...this.state}
        setOpen={this.setOpen}
        dateFormat={
          this.props.dateFormatCalendar ??
          DatePicker.defaultProps.dateFormatCalendar
        }
        onSelect={this.handleSelect}
        onClickOutside={this.handleCalendarClickOutside}
        holidays={getHolidaysMap(this.modifyHolidays())}
        outsideClickIgnoreClass={this.props.outsideClickIgnoreClass}
        onDropdownFocus={this.handleDropdownFocus}
        onTimeChange={this.handleTimeChange}
        className={this.props.calendarClassName}
        container={this.props.calendarContainer}
        handleOnKeyDown={this.props.onKeyDown}
        handleOnDayKeyDown={this.onDayKeyDown}
        setPreSelection={this.setPreSelection}
        dropdownMode={
          this.props.dropdownMode ?? DatePicker.defaultProps.dropdownMode
        }
      >
        {this.props.children}
      </Calendar>
    );
  };

  renderAriaLiveRegion = () => {
    const { locale } = this.props;
    const dateFormat =
      this.props.dateFormat ?? DatePicker.defaultProps.dateFormat;
    const isContainsTime =
      this.props.showTimeInput || this.props.showTimeSelect;
    const longDateFormat = isContainsTime ? "PPPPp" : "PPPP";
    let ariaLiveMessage;

  const startOfMonth = getStartOfMonth(date);
  const endOfMonth = getEndOfMonth(date);

  const totalDays = differenceInDays(endOfMonth, startOfMonth);

  let preSelectedDate = null;

  for (let dayIdx = 0; dayIdx <= totalDays; dayIdx++) {
    const processingDate = addDays(startOfMonth, dayIdx);

    if (!isDayDisabled(processingDate, this.props)) {
      preSelectedDate = processingDate;
      break;
    }
  }

  return preSelectedDate;
};

handleMonthChange = (date: Date): void => {
  const enabledPreSelectionDate =
    this.getEnabledPreSelectionDateForMonth(date) ?? date;

  this.handleCustomMonthChange(enabledPreSelectionDate);
  if (this.props.adjustDateOnChange) {
    this.props.onSelect(enabledPreSelectionDate);
    this.props.setOpen?.(true);
  }

  this.props.setPreSelection &&
    this.props.setPreSelection(enabledPreSelectionDate);
};

handleCustomMonthChange = (date: Date): void => {
  this.props.onMonthChange?.(date);
  this.setState({ isRenderAriaLiveMessage: true });
};

handleMonthYearChange = (date: Date): void => {
  this.handleYearChange(date);
  this.handleMonthChange(date);
};

changeYear = (year: number): void => {
  this.setState(
    ({ date }) => ({
      date: setYear(date, Number(year)),
    }),
    () => this.handleYearChange(this.state.date),
  );
};

changeMonth = (month: number): void => {
  this.setState(
    ({ date }) => ({
      date: setMonth(date, Number(month)),
    }),
    () => this.handleMonthChange(this.state.date),
  );
};

changeMonthYear = (monthYear: Date): void => {
  this.setState(
    ({ date }) => ({
      date: setYear(setMonth(date, getMonth(monthYear)), getYear(monthYear)),
    }),
    () => this.handleMonthYearChange(this.state.date),
  );
};

header = (date: Date = this.state.date): React.ReactElement[] => {
  // Return empty array if date is invalid
  if (!isValid(date)) {
    return [];
  }

  const disabled = this.props.disabled;
  const startOfWeek = getStartOfWeek(
    date,
    this.props.locale,
    this.props.calendarStartDay,
  );

  const dayNames: React.ReactElement[] = [];
  if (this.props.showWeekNumbers) {
    dayNames.push(
      <div
        key="W"
        className={`react-datepicker__day-name ${disabled ? "react-datepicker__day-name--disabled" : ""}`}
        role="columnheader"
      >
        <span className="react-datepicker__sr-only">Week number</span>
        <span aria-hidden="true">{this.props.weekLabel || "#"}</span>
      </div>,
    );
  }
  return dayNames.concat(
    [0, 1, 2, 3, 4, 5, 6].map((offset) => {
      const day = addDays(startOfWeek, offset);
      const weekDayName = this.formatWeekday(day, this.props.locale);

      const weekDayClassName = this.props.weekDayClassName
        ? this.props.weekDayClassName(day)
        : undefined;

      return (
        <div
          key={offset}
          role="columnheader"
          className={clsx(
            "react-datepicker__day-name",
            weekDayClassName,
            disabled ? "react-datepicker__day-name--disabled" : "",
          )}
        >
          <span className="react-datepicker__sr-only">
            {formatDate(day, "EEEE", this.props.locale)}
          </span>
          <span aria-hidden="true">{weekDayName}</span>
        </div>
      );
    }),
  );
};

formatWeekday = (day: Date, locale?: Locale): string => {
  if (this.props.formatWeekDay) {
    return getFormattedWeekdayInLocale(day, this.props.formatWeekDay, locale);
  }
  return this.props.useWeekdaysShort
    ? getWeekdayShortInLocale(day, locale)
    : getWeekdayMinInLocale(day, locale);
};

decreaseYear = (): void => {
  this.setState(
    ({ date }) => ({
      date: subYears(
        date,
        this.props.showYearPicker
          ? (this.props.yearItemNumber ??
              Calendar.defaultProps.yearItemNumber)
          : 1,
      ),
    }),
    () => this.handleYearChange(this.state.date),
  );
};

clearSelectingDate = (): void => {
  this.setState({ selectingDate: undefined });
};

renderPreviousButton = (): React.ReactElement | void => {
  if (this.props.renderCustomHeader) {
    return;
  }

  const monthsShown =
    this.props.monthsShown ?? Calendar.defaultProps.monthsShown;
  const monthsToSubtract = this.props.showPreviousMonths
    ? monthsShown - 1
    : 0;
  const monthSelectedIn = this.props.monthSelectedIn ?? monthsToSubtract;
  const fromMonthDate = subMonths(this.state.date, monthSelectedIn);

  let allPrevDaysDisabled;
  switch (true) {
    case this.props.disabled:
      allPrevDaysDisabled = true;
      break;
    case this.props.showMonthYearPicker:
      allPrevDaysDisabled = yearDisabledBefore(this.state.date, this.props);
      break;
    case this.props.showYearPicker:
      allPrevDaysDisabled = yearsDisabledBefore(this.state.date, this.props);
      break;
    case this.props.showQuarterYearPicker:
      allPrevDaysDisabled = quarterDisabledBefore(
        this.state.date,
        this.props,
      );
      break;
    default:
      allPrevDaysDisabled = monthDisabledBefore(fromMonthDate, this.props);
      break;
  }

  if (
    (!(
    <div
      className={`react-datepicker__header__dropdown react-datepicker__header__dropdown--${this.props.dropdownMode}`}
      onFocus={this.handleDropdownFocus}
    >
      {this.renderMonthDropdown(i !== 0)}
      {this.renderMonthYearDropdown(i !== 0)}
      {this.renderYearDropdown(i !== 0)}
    </div>
  </div>
);

renderCustomHeader = (headerArgs: { monthDate: Date; i: number }) => {
  const { monthDate, i } = headerArgs;

  if (
    (this.props.showTimeSelect && !this.state.monthContainer) ||
    this.props.showTimeSelectOnly
  ) {
    return null;
  }

  const { showYearPicker, yearItemNumber } = this.props;

  let visibleYearsRange;
  if (showYearPicker) {
    const { startPeriod: startYear, endPeriod: endYear } = getYearsPeriod(
      monthDate,
      yearItemNumber,
    );
    visibleYearsRange = {
      startYear,
      endYear,
    };
  }

  const prevMonthButtonDisabled = monthDisabledBefore(
    this.state.date,
    this.props,
  );

  const nextMonthButtonDisabled = monthDisabledAfter(
    this.state.date,
    this.props,
  );

  const prevYearButtonDisabled = yearDisabledBefore(
    this.state.date,
    this.props,
  );

  const nextYearButtonDisabled = yearDisabledAfter(
    this.state.date,
    this.props,
  );

  return (
    <div
      className="react-datepicker__header react-datepicker__header--custom"
      onFocus={this.props.onDropdownFocus}
    >
      {this.props.renderCustomHeader?.({
        ...this.state,
        ...(showYearPicker && { visibleYearsRange }),
        customHeaderCount: i,
        monthDate,
        changeMonth: this.changeMonth,
        changeYear: this.changeYear,
        decreaseMonth: this.decreaseMonth,
        increaseMonth: this.increaseMonth,
        decreaseYear: this.decreaseYear,
        increaseYear: this.increaseYear,
        prevMonthButtonDisabled,
        nextMonthButtonDisabled,
        prevYearButtonDisabled,
        nextYearButtonDisabled,
      })}
    </div>
  );
};

renderYearHeader = ({
  monthDate,
}: {
  monthDate: Date;
}): React.ReactElement => {
  const {
    showYearPicker,
    yearItemNumber = Calendar.defaultProps.yearItemNumber,
  } = this.props;
  const { startPeriod, endPeriod } = getYearsPeriod(
    monthDate,
    yearItemNumber,
  );
  return (
    <div className="react-datepicker__header react-datepicker-year-header">
      {showYearPicker ? `${startPeriod} - ${endPeriod}` : getYear(monthDate)}
    </div>
  );
};

renderHeader = ({
  monthDate,
  i = 0,
}: {
  monthDate: Date;
  i?: number;
}): React.ReactElement | null => {
  const headerArgs = { monthDate, i };
  switch (true) {
    case this.props.renderCustomHeader !== undefined:
      return this.renderCustomHeader(headerArgs);
    case this.props.showMonthYearPicker ||
      this.props.showQuarterYearPicker ||
      this.props.showYearPicker:
      return this.renderYearHeader(headerArgs);
    default:
      return this.renderDefaultHeader(headerArgs);
  }
};

renderMonths = (): React.ReactElement[] | undefined => {
  if (this.props.showTimeSelectOnly || this.props.showYearPicker) {
    return;
  }

  const monthList: React.ReactElement[] = [];
  const monthsShown =
    this.props.monthsShown ?? Calendar.defaultProps.monthsShown;
  const monthsToSubtract = this.props.showPreviousMonths
    ? monthsShown - 1
    : 0;
  const fromMonthDate =
    this.props.showMonthYearPicker || this.props.showQuarterYearPicker
      ? addYears(this.state.date, monthsToSubtract)
      : subMonths(this.state.date, monthsToSubtract);
  const monthSelectedIn = this.props.monthSelectedIn ?? monthsToSubtract;
  for (let i = 0; i < monthsShown; ++i) {
    const monthsToAdd = i - monthSelectedIn + monthsToSubtract;
    const monthDate =
      this.props.showMonthYearPicker || this.props.showQuarterYearPicker
        ? addYears(fromMonthDate, monthsToAdd)
        : addMonths(fromMonthDate, monthsToAdd);
    const monthKey = `month-${i}`;
    const monthShowsDuplicateDaysEnd = i < monthsShown - 1;
    const monthShowsDuplicateDaysStart = i > 0;
    monthList.push(
      <div
        key={monthKey}
        ref={(div) => {
          this.monthContainer = div ?? undefined;
        }}
        className="react-datepicker__month-container"
      >
        {this.renderHeader({ monthDate, i })}
        <Month
          {...Calendar.defaultProps}
          {...this.props}
          containerRef={this.containerRef}
          ariaLabelPrefix={this.props.monthAriaLabelPrefix}
          day={monthDate}
          onDayClick={this.handleDayClick}
          handleOnKeyDown={this.props.handleOnDayKeyDown}
          handleOnMonthKeyDown={this.props.handleOnKeyDown}
          onDayMouseEnter={this.handleDayMouseEnter}
          onMouseLeave={this.handleMonthMouseLeave}
          orderInDisplay={i}

  let instance: DatePicker | null = null;
  render(
    <DatePicker
      ref={(node) => {
        instance = node;
      }}
      selected={newDate("2015-12-15")}
    />,
  );
  expect(instance).toBeTruthy();
  act(() => {
    instance!.clear();
  });

  expect(instance!.state.inputValue).toBeNull();
});
it("should not open when open is false and input is focused", () => {
  const { container } = render(<DatePicker open={false} />);
  const input = safeQuerySelector(container, "input");
  fireEvent.focus(input);
  expect(container.querySelector(".react-datepicker")).toBeNull();
});
it("should open when open is true", () => {
  const { container } = render(<DatePicker open />);
  expect(container.querySelector(".react-datepicker")).not.toBeNull();
});
it("should fire onInputClick when input is clicked", () => {
  const onInputClickSpy = jest.fn();
  const { container } = render(<DatePicker onInputClick={onInputClickSpy} />);
  const input = safeQuerySelector(container, "input");
  fireEvent.click(input);
  expect(onInputClickSpy).toHaveBeenCalledTimes(1);
});

it("should set monthSelectedIn to 0 if monthsShown prop changes", () => {
  let instance: DatePicker | null = null;
  const { rerender } = render(
    <DatePicker
      ref={(node) => {
        instance = node;
      }}
      monthsShown={2}
      inline
    />,
  );
  expect(instance).toBeTruthy();
  act(() => {
    (
      instance!.state as unknown as { monthSelectedIn: number }
    ).monthSelectedIn = 1;
  });
  expect(instance!.state.monthSelectedIn).toEqual(1);

  rerender(
    <DatePicker
      ref={(node) => {
        instance = node;
      }}
      monthsShown={1}
      inline
    />,
  );

  expect(instance!.state.monthSelectedIn).toEqual(0);
});

it("should set monthSelectedIn to 0 when selectsRange is true", () => {
  let instance: DatePicker | null = null;
  const { rerender } = render(
    <DatePicker
      ref={(node) => {
        instance = node;
      }}
      monthsShown={2}
      inline
    />,
  );
  expect(instance).toBeTruthy();
  act(() => {
    (
      instance!.state as unknown as { monthSelectedIn: number }
    ).monthSelectedIn = 1;
  });
  expect(instance!.state.monthSelectedIn).toEqual(1);

  rerender(
    <DatePicker
      ref={(node) => {
        instance = node;
      }}
      monthsShown={2}
      inline
      selectsRange
    />,
  );

  expect(instance!.state.monthSelectedIn).toEqual(0);
});

it("should disable non-jumping if prop focusSelectedMonth is true", () => {
  let instance: DatePicker | null = null;
  const { container } = render(
    <DatePicker
      ref={(node) => {
        instance = node;
      }}
      inline
      monthsShown={2}
      focusSelectedMonth
    />,
  );
  const dayButtonInline = container.querySelectorAll(
    ".react-datepicker__day",
  )[40];
  expect(dayButtonInline).toBeTruthy();
  fireEvent.click(dayButtonInline!);
  expect(instance).toBeTruthy();
  expect(instance!.state.monthSelectedIn).toEqual(undefined);
});

it("should show the popper arrow when showPopperArrow is true", () => {
  const { container } = render(<DatePicker showPopperArrow />);
  const input = safeQuerySelector(container, "input");
  fireEvent.click(input);

  const arrow = container.querySelector(".react-datepicker__triangle");

  expect(arrow).not.toBeNull();
